function formatTimestamp(timestamp) {
	if (!timestamp || timestamp <= 0) {
		return "";
	}
	let date = new Date(timestamp * 1000);
	if (date.getTime() <= 0 || isNaN(date.getTime())) {
		return "";
	}
	let year = date.getFullYear();
	let month = String(date.getMonth() + 1).padStart(2, '0');
	let day = String(date.getDate()).padStart(2, '0');
	let hours = String(date.getHours()).padStart(2, '0');
	let minutes = String(date.getMinutes()).padStart(2, '0');
	let seconds = String(date.getSeconds()).padStart(2, '0');
	return `${year}-${month}-${day} ${hours}:${minutes}:${seconds}`;
}

function getNovelStatusByMap(step) {
	const statusMap = {
		"0": "暂停",
		"1": "连载",
		"2": "完结"
	};
	return statusMap[String(step)] || "未知";
}

function formatDate(datetime) {
	if (!datetime || datetime <= 0) return "";
	const now = Math.floor(Date.now() / 1000);
	const diff = now - datetime;
	if (diff < 0) return "刚刚";
	if (diff < 60) return "刚刚";
	if (diff < 3600) return `${Math.floor(diff / 60)}分钟前`;
	if (diff < 86400) return `${Math.floor(diff / 3600)}小时前`;
	if (diff < 604800) return `${Math.floor(diff / 86400)}天前`;
	if (diff < 2592000) return `${Math.floor(diff / 604800)}星期前`;
	if (diff < 31536000) return `${Math.floor(diff / 2592000)}个月前`;
	return `${Math.floor(diff / 31536000)}年前`;
}

function encode(data) {
	const {java} = this;
	return java.createSymmetricCrypto("DES/CBC/PKCS5Padding", String("KW8Dvm2N"), String("1ae2c94b")).encryptBase64(data)
}

function M(e) {
	const {source} = this;
	return String(source.getLoginInfoMap()[e] ?? "")
}

function Map(e, that) {
	const {source} = that || this;
	return getHeaderMap(that || this)[e] ?? ""
}

function getHeaderMap(_) {
	const {source,java} = _ || this;
	let infomap = String(source.getLoginHeader()).replace(/^#/, '');
	infomap = (infomap != "null" && infomap != "" && infomap != null) ? infomap : "{}";
	return JSON.parse(infomap);
}

function setHeaders() {
	const {source,java} = this;
	let map = getHeaderMap(this);
	for (let i = 0; i < arguments.length; i++) {
		let k = arguments[i].split("=")[0];
		let v = arguments[i].split("=")[1];
		map[k] = v;
	}
	source.putLoginHeader("#" + JSON.stringify(map))
}

function deleteHead(paths) {
	const {java,source} = this;
	var result = this.getHeaderMap()
	var pathsToDelete = Array.isArray(paths) ? paths : [paths];
	for (var i = 0; i < pathsToDelete.length; i++) {
		var path = pathsToDelete[i];
		var parts = path.split('.');
		var current = result;
		for (var j = 0; j < parts.length - 1; j++) {
			var part = parts[j];
			if (current && typeof current === 'object' && current.hasOwnProperty(part)) {
				current = current[part];
			} else {
				current = null;
				break;
			}
		}
		if (current && typeof current === 'object') {
			var lastKey = parts[parts.length - 1];
			if (current.hasOwnProperty(lastKey)) {
				delete current[lastKey];
			}
		}
	}
	source.putLoginHeader("#" + JSON.stringify(result))
	return result;
}

function bDe(d, that) {
	const {java} = that || this;
	let re, token, novelId, chapterId;
	if (/^http/.test(d)) {
		token = /\d+_[\w\d]{16,}/.test(d) ? "token=" + d.match(/\d+_[\w\d]{16,}/)[0] : "token=";
		novelId = d.match(/novelId=\d+/)[0];
		chapterId = /chapterId=\d+/.test(d) ? "&" + d.match(/chapterId=\d+/)[0] : "";
		re = `${token}&${novelId}${chapterId}`;
	} else {
		re = String(java.base64Decode(String(d).match(/base64,([^,]+),*/)[1]));
	}
	return re
}

