function toScan() {
	try {
		headers = {
			"source": "android",
			"versioncode": Map("versionCode"),
			"version-code": Map("versionCode")
		}
		let e = java.ajax("https://android.jjwxc.com/app.jjwxc/android/reading/Login/scanCodeLogin?versionCode=" + Map("versionCode") + "," + JSON.stringify({headers: headers}));
		let eData = JSON.parse(e).data;
		let jjscanurl = "https://www.jjwxc.net?action=scanCode&jjreader_key=" + eData.jjreader_key + "&device_key=" + eData.device_key;
		let enjj = encodeURIComponent(jjscanurl);
		let html = `<title>扫码二维码</title><meta name="viewport" content="width=device-width,initial-scale=1.0"><style>body{margin:0;padding:0}</style><div style="text-align:center;padding:20px;"><h3 style="color:#2e9918">晋江扫码登录</h3><p>请用已登录新版晋江的手机扫码【截图后去晋江扫码】</p><p>请在当前登录了晋江账号的手机上进入：<br>晋江小说阅读App→我的→点击右上角"扫码"图标</p><img style="width:300px;height:300px;border:1px solid #ccc" src="https://api.qrtool.cn/?text=${enjj}"><p style="color:red;font-weight:bold">请扫码授权后，再点右上角的"✓"，不要提前点，否则要重新扫码</p></div>`;
		let u = java.startBrowserAwait(`data:text/html;charset=UTF-8,${encodeURIComponent(html)}`, "扫码登录", false).body();
		if (u) {
			headers["Content-Type"] = "application/octet-stream"
			let checkLogin = "https://android.jjwxc.com/app.jjwxc/android/reading/Login/checkJjreaderLogin";
			let body = encode(JSON.stringify({
				"versionCode": Map("versionCode"),
				"jjreader_key": eData.jjreader_key,
				"device_key": eData.device_key
			}));
			checkLoginpost = {
				"method": "POST",
				"body": body,
				"headers": headers
			}
			checkLogin = checkLogin + "," + JSON.stringify(checkLoginpost);
			let t = java.ajax(checkLogin);
			t = JSON.parse(t).data?.token ?? JSON.parse(t).message;
			if (/\d+_\w{32}/.test(t)) {
				setHeaders(`token=${t}`);
				java.toast("登录成功")
			} else {
				java.toast(t)
			}
		}
	} catch (e) {
		java.log(e);
		java.toast("扫码登录失败，请重试")
	}
}

function SearchSet() {
	try {
