ent.getElementById(key+'-text').textContent=name+'('+value+')';var btns=document.getElementById(key+'-btns').children;for(var btn of btns)btn.classList.toggle('selected',btn.textContent===name);document.getElementById('result').textContent=current.type+','+current.sort;}init(document.getElementById('type-btns'),config.types,'type');init(document.getElementById('sort-btns'),config.sorts,'sort');select('type',typeValue,config.types[typeValue]);select('sort',sortValue,config.sorts[sortValue]);</script></body></html>`;
        let encodeURI = `data:text/html;charset=UTF-8,${encodeURIComponent(html)}`;
