	if (html.indexOf('class="volumes') > -1) {
		var text = String(item.text())
			.replace(new RegExp(String(book.name), 'g'), '')
			.replace(new RegExp("（.*", 'g'), '')
			.replace(new RegExp("^正文$", 'g'), '');

		if (text) {
			list.push({
				text: `📜${text}`,
				volume: true
			});
		}
	} else {
		var links = item.select("a");
		for (var j = 0; j < links.size(); j++) {
			var a = links.get(j);
			list.push({
				text: a.text(),
				href: a.attr("href")
			});
		}
	}
}

list;

